class Solution {
    public int maxFreq(String s, int maxLetters, int minSize, int maxSize) {
        int count = 0;
        int maxCount = 0;
        int maxLettersCount = 0;
        int minSizeCount = 0;
        int maxSizeCount = 0;

        for (int i = 0; i < s.length(); i++) {
            int currentLettersCount = 0;
            int currentSizeCount = 0;

            while (i + currentSizeCount < s.length() && currentSizeCount <= maxSize) {
                for (int j = i; j < i + currentSizeCount; j++) {
                    if (s.charAt(j) != s.charAt(i)) {
                        currentLettersCount++;
                    }
                }
                currentSizeCount++;
                if (currentLettersCount <= maxLetters && currentSizeCount <= maxSize) {
                    count++;
                    if (count > maxCount) {
                        maxCount = count;
                        maxLettersCount = currentLettersCount;
                        maxSizeCount = currentSizeCount;
                    }
                }
            }
        }
        return maxCount;
    }
}
